-- Struktúra mentése trigger studio13_csany_zeg. foto_upl_1
DROP TRIGGER IF EXISTS `foto_upl_1`;
SET @OLDTMP_SQL_MODE=@@SQL_MODE, SQL_MODE='STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION';
DELIMITER //
CREATE DEFINER=`szaloky.adam`@`%` TRIGGER `foto_upl_1` AFTER INSERT ON `webbolt_fotok` FOR EACH ROW BEGIN
	-- Az első beszúrás után van IMG ezért termek FOTOLINK null-ra allitom 
	UPDATE webbolt_termekek SET FOTOLINK = NULL WHERE ID_TERMEK = NEW.ID_TERMEK;
END//
DELIMITER ;
SET SQL_MODE=@OLDTMP_SQL_MODE;

-- Struktúra mentése trigger studio13_csany_zeg. foto_upl_2
DROP TRIGGER IF EXISTS `foto_upl_2`;
SET @OLDTMP_SQL_MODE=@@SQL_MODE, SQL_MODE='STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION';
DELIMITER //
CREATE DEFINER=`szaloky.adam`@`%` TRIGGER `foto_upl_2` AFTER UPDATE ON `webbolt_fotok` FOR EACH ROW BEGIN
-- Ha volt már record a táblában de eddig null volt és most kap egy értéket akkor a termek FOTOLINK null
 if (NEW.IMG IS NOT null) then UPDATE webbolt_termekek SET FOTOLINK = NULL WHERE ID_TERMEK = NEW.ID_TERMEK; END if;
END//
DELIMITER ;
SET SQL_MODE=@OLDTMP_SQL_MODE;

-- Struktúra mentése trigger studio13_csany_zeg. rendeleskor
DROP TRIGGER IF EXISTS `rendeleskor`;
SET @OLDTMP_SQL_MODE=@@SQL_MODE, SQL_MODE='STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION';
DELIMITER //
CREATE DEFINER=`szaloky.adam`@`%` TRIGGER `rendeleskor` AFTER INSERT ON `webbolt_rendeles_tetelei` FOR EACH ROW BEGIN

  UPDATE webbolt_termekek
  SET MENNYISEG = GREATEST(0, CAST(MENNYISEG AS SIGNED) - CAST(NEW.MENNYISEG AS SIGNED))
      -- CAST(MENNYISEG AS SIGNED) az "UNSIGNED out of range" hiba elkerülése érdekében
  WHERE ID_TERMEK = NEW.ID_TERMEK;

  -- Frissítjük a kosár tételeket, hogy ne legyen nagyobb a mennyiség, mint a termékekből elérhető készlet
  UPDATE webbolt_kosar_tetelei k
  JOIN webbolt_termekek t ON k.ID_TERMEK = t.ID_TERMEK
  SET k.MENNYISEG = LEAST(k.MENNYISEG, t.MENNYISEG)
  WHERE t.ID_TERMEK = NEW.ID_TERMEK;

  -- Ha a kosárban lévő mennyiség 0 lett, töröljük azt a tételt
  DELETE FROM webbolt_kosar_tetelei
  WHERE ID_TERMEK = NEW.ID_TERMEK AND MENNYISEG = 0;

END//
DELIMITER ;
SET SQL_MODE=@OLDTMP_SQL_MODE;

-- Struktúra mentése trigger studio13_csany_zeg. termek_delete
DROP TRIGGER IF EXISTS `termek_delete`;
SET @OLDTMP_SQL_MODE=@@SQL_MODE, SQL_MODE='STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION';
DELIMITER //
CREATE DEFINER=`szaloky.adam`@`%` TRIGGER `termek_delete` AFTER DELETE ON `webbolt_termekek` FOR EACH ROW BEGIN
   -- Kitörli a webbolt_termekek-ből törölt rekordod minden kosárból--
   -- FONTOS hogy olyan terméket nem lehet törölni amiből valaki rendelt már (restriction)-- 
	DELETE FROM webbolt_kosar_tetelei WHERE ID_TERMEK = OLD.ID_TERMEK;
	
		
	-- Ellenőrizzük a termékek számát az OLD.ID_KATEGORIA kategóriában
	-- Ha az előző táblában lévő kategória ID-hoz már nincs termék, töröljük a kategóriát.
	DELETE FROM webbolt_kategoriak
	WHERE ID_KATEGORIA = OLD.ID_KATEGORIA
	AND (
	    SELECT COUNT(t.ID_TERMEK)
	    FROM webbolt_termekek t
	    WHERE t.ID_KATEGORIA = OLD.ID_KATEGORIA
	) = 0;
END//
DELIMITER ;
SET SQL_MODE=@OLDTMP_SQL_MODE;

-- Struktúra mentése trigger studio13_csany_zeg. termek_update_after
DROP TRIGGER IF EXISTS `termek_update_after`;
SET @OLDTMP_SQL_MODE=@@SQL_MODE, SQL_MODE='STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION';
DELIMITER //
CREATE DEFINER=`szaloky.adam`@`%` TRIGGER `termek_update_after` AFTER UPDATE ON `webbolt_termekek` FOR EACH ROW BEGIN
  -- before-ban van a mennyiség-aktivitás szabályozás

  -- Csak akkor fut le, ha a mennyiség csökkent vagy inaktív lett
  IF (NEW.MENNYISEG < OLD.MENNYISEG) OR (OLD.AKTIV = 'Y' AND NEW.AKTIV = 'N') THEN

    -- Csökkentjük a mennyiséget a kosárban
    UPDATE webbolt_kosar_tetelei k
    SET k.MENNYISEG = LEAST(k.MENNYISEG, CAST(NEW.MENNYISEG AS SIGNED))
    WHERE k.ID_TERMEK = NEW.ID_TERMEK;

    -- Ha inaktív lett, töröljük az összes kosártételt
    IF NEW.AKTIV = 'N' THEN
      DELETE FROM webbolt_kosar_tetelei
      WHERE ID_TERMEK = NEW.ID_TERMEK;

    ELSE
      -- Ha aktív maradt, de a mennyisége 0-ra csökkent, töröljük a 0-s tételeket a kosarakból
      DELETE FROM webbolt_kosar_tetelei
      WHERE ID_TERMEK = NEW.ID_TERMEK AND MENNYISEG = 0;

    END IF;
  END IF;
  
	-- Ellenőrizzük a termékek számát az OLD.ID_KATEGORIA kategóriában
	-- Ha az előző táblában lévő kategória ID-hoz már nincs termék, töröljük a kategóriát.
	DELETE FROM webbolt_kategoriak
	WHERE ID_KATEGORIA = OLD.ID_KATEGORIA
	AND (
	    SELECT COUNT(t.ID_TERMEK)
	    FROM webbolt_termekek t
	    WHERE t.ID_KATEGORIA = OLD.ID_KATEGORIA
	) = 0;
	
	-- Feltöltött foto törlése ha van link
	if(NEW.FOTOLINK IS NOT null) then UPDATE webbolt_fotok SET IMG = NULL, FILENAME = null WHERE ID_TERMEK = NEW.ID_TERMEK; END if;
	
END//
DELIMITER ;
SET SQL_MODE=@OLDTMP_SQL_MODE;

-- Struktúra mentése trigger studio13_csany_zeg. termek_update_before
DROP TRIGGER IF EXISTS `termek_update_before`;
SET @OLDTMP_SQL_MODE=@@SQL_MODE, SQL_MODE='STRICT_TRANS_TABLES,ERROR_FOR_DIVISION_BY_ZERO,NO_AUTO_CREATE_USER,NO_ENGINE_SUBSTITUTION';
DELIMITER //
CREATE DEFINER=`szaloky.adam`@`%` TRIGGER `termek_update_before` BEFORE UPDATE ON `webbolt_termekek` FOR EACH ROW BEGIN
  -- Azért kell ez mivel after-updateval nem tudnám változtatni az aktivitasat hiaba lenne 0 a mennyiseg
  IF NEW.MENNYISEG = 0 THEN
    SET NEW.AKTIV = 'N';
  END IF;
END//
DELIMITER ;
SET SQL_MODE=@OLDTMP_SQL_MODE;

